import React, { useState } from 'react'
import { Container, Divider, Grid, Paper, TextField, makeStyles, Button, Box, IconButton, InputAdornment, Tooltip, Typography, Dialog, DialogTitle, DialogContent, DialogContentText, DialogActions, useTheme, useMediaQuery } from '@material-ui/core'
import StudentActivities from '../components/StudentActivities'
import { AttachFileRounded } from '@material-ui/icons'
import { useLocation } from 'react-router-dom'

const useStyle = makeStyles(theme => {
    return {
        paper: {
            padding: theme.spacing(2),
            borderRadius: '4px',
            width: '100%',
            maxWidth: '500px',
            background: '#fefefe',
            marginTop: theme.spacing(5),
            boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;'
        },
        input: {
            display: 'none'
        }
    }
})

export default function TeacherFeed() {

    const location = useLocation()
    const subject = location.search.slice(1)
    const subjectName = subject.replace('%20', ' ')

    const [open, setOpen] = React.useState(false);
    const theme = useTheme();
    const fullScreen = useMediaQuery(theme.breakpoints.down('sm'));
  
    const handleClickOpen = () => {
      setOpen(true);
    };
  
    const handleClose = () => {
      setOpen(false);
    };

    const classes = useStyle()

    const [activities, setActivities] = useState([
        { title: 'Assignment 1 mahaba mabahaba', body: 'May 11', id: 1 },
        { title: 'Assignment 2 mahaba mabahaba', body: 'May 2', id: 2 },
        { title: 'Assignment 3 mahaba mabahaba', body: 'May 3', id: 3 },
        { title: 'Assignment 4 mahaba mabahaba', body: 'May 4', id: 4 },
        { title: 'Assignment 5 mahaba mabahaba', body: 'May 5', id: 5 },
        { title: 'Assignment 6 mahaba mabahaba', body: 'May 6', id: 6 },
        { title: 'Assignment 7 mahaba mabahaba', body: 'May 7', id: 7 },
        { title: 'Assignment 8 mahaba mabahaba', body: 'May 8', id: 8 },
        { title: 'Assignment 9 mahaba mabahaba', body: 'May 9', id: 9 },
        { title: 'Assignment 10 mahaba mabahaba', body: 'May 10', id: 10 },
    ])
    return (
        <div >

            <Box>
                <h1>{subjectName}</h1>
                <p>BSCpE - 3A</p>
            </Box>
            <Container maxWidth='sm'>
                <Grid container spacing={3}>

                    <Grid item xs={12}>
                        <Box className={classes.paper} >
                            <Typography variant='h5'>
                                Create post
                            </Typography>

                            <TextField variant='filled' label='Title' margin='normal' fullWidth />

                            <TextField
                                variant='filled' color='secondary' label='Announcement' minRows={5} margin='normal' multiline fullWidth
                                InputProps={{
                                    endAdornment:
                                        <InputAdornment position="end">
                                            <input className={classes.input} type="file" accept='image/*' id='attach-file' />
                                            <label htmlFor="attach-file">
                                                <IconButton component='span'><Tooltip title='Attach a file' placement='right-start' ><AttachFileRounded /></Tooltip></IconButton>
                                            </label>
                                        </InputAdornment>
                                }}
                            />

                            <Button variant='contained' color='secondary' size='large' onClick={handleClickOpen} fullWidth disableElevation >Post</Button>
                        </Box>

                        <Dialog
                            fullScreen={fullScreen}
                            open={open}
                            onClose={handleClose}
                            aria-labelledby="responsive-dialog-title"
                        >
                            <DialogTitle id="responsive-dialog-title">{"Confirmation"}</DialogTitle>
                            <DialogContent>
                                <DialogContentText>
                                Are you sure you want to post this?
                                </DialogContentText>
                            </DialogContent>
                            <DialogActions>
                                <Button autoFocus onClick={handleClose} color="primary">
                                    Disagree
                                </Button>
                                <Button onClick={handleClose} color="primary" autoFocus>
                                    Agree
                                </Button>
                            </DialogActions>
                        </Dialog>
                    </Grid>

                    {activities.map(activity => (
                        <Grid item xs={12} key={activity.id}>
                            <StudentActivities activity={activity} />
                        </Grid>
                    ))}

                </Grid>
            </Container>
        </div>
    )
}
